    ///////////////////////////////////////////////////////////////////////////
    // Implement APB I/O map to DMA interface
    // Write side
    always @(posedge clk_i)
        begin
            if(~(rst_ni && ~rst_8))
                begin
                    core_lock_reg <= 'b0; 
                    start_reg <= 'b0; 
                    length_reg <= 'b0; 
                    source_addr_lsb_reg<= 'b0; 
                    source_addr_msb_reg<= 'b0; 
                    dest_addr_lsb_reg  <= 'b0; 
                    dest_addr_msb_reg  <= 'b0; 
                    done_reg  <= 'b0; 
                    end_reg  <= 'b0; 
                end
            else if(en && we)
                case(address[7:3])
                    0:
                        start_reg <= wdata;
                    1:
                        length_reg <= wdata;
                    2:
                        source_addr_lsb_reg <= wdata;
                    3:
                        source_addr_msb_reg <= wdata;

